define("aiplacement_translate/placement",["core/templates","core/ajax","core/copy_to_clipboard","core/notification","core_ai/policy","core_ai/helper","core/str"],(function(Templates,Ajax,_copyToClipboard,Notification,Policy,AIHelper,Str){const SEL={DRAWER:"#ai-translate-drawer",CLOSE:"#ai-translate-close",BODY:"#ai-translate-body",RESULT:"#ai-translate-result",LANG:"#ai-translate-lang",BTN:".ai-translate-btn",PAGE:"#page",MAIN:'[role="main"]'};const AITranslate=class{constructor(userId,contextId){this.userId=userId;this.contextId=contextId;this.drawer=document.querySelector(SEL.DRAWER);this.result=document.querySelector(SEL.RESULT);this.langSelect=document.querySelector(SEL.LANG);this.page=document.querySelector(SEL.PAGE);this.cancelled=false;this._listen()}_listen(){document.addEventListener("click",async e=>{if(e.target.closest(SEL.BTN)){e.preventDefault();this._open()}if(e.target.closest(SEL.CLOSE)){e.preventDefault();this._close()}});this.langSelect?.addEventListener("change",async()=>{const lang=this.langSelect.value;if(!lang)return;const ok=await Policy.getPolicyStatus(this.userId);if(!ok){this._showPolicy(lang);return}this._translate(lang)});document.addEventListener("keydown",e=>{if(e.key==="Escape"&&this.drawer.classList.contains("show")){this._close()}})}_open(){this.drawer.classList.add("show");if(!this.page.classList.contains("show-drawer-right")){this.page.classList.add("show-drawer-right");this.drawer.dataset.removepadding="1"}}_close(){this.drawer.classList.remove("show");if(this.drawer.dataset.removepadding==="1"){this.page.classList.remove("show-drawer-right");this.drawer.dataset.removepadding="0"}}_showPolicy(lang){Templates.render("core_ai/policyblock",{}).then(html=>{this.result.innerHTML=html;const accept=this.result.querySelector('[data-action="accept"]');const decline=this.result.querySelector('[data-action="decline"]');accept?.addEventListener("click",e=>{e.preventDefault();Policy.acceptPolicy().then(()=>this._translate(lang)).catch(Notification.exception)});decline?.addEventListener("click",e=>{e.preventDefault();this._close()});return}).catch(Notification.exception)}async _translate(lang){this.cancelled=false;const loadingHtml=await Templates.render("aiplacement_courseassist/loading",{});this.result.innerHTML=loadingHtml;const cancelBtn=this.result.querySelector('[data-action="cancel"]');cancelBtn?.addEventListener("click",e=>{e.preventDefault();this.cancelled=true;this.result.innerHTML=""});const request={methodname:"aiplacement_translate_translate_text",args:{contextid:this.contextId,prompttext:this._getPageText(),targetlanguage:lang}};try{const res=await Ajax.call([request])[0];if(this.cancelled)return;if(res.error){this._showError(res.error,res.errormessage);return}const content=AIHelper.formatResponse(res.generatedcontent);this._showResponse(content,lang)}catch(err){window.console.error(err);this._showError()}}async _showResponse(content,lang){const opt=this.langSelect.querySelector('option[value="'+lang+'"]');const langName=opt?opt.textContent:lang;const heading=await Str.getString("aitranslation","aiplacement_translate",langName);const html=await Templates.render("aiplacement_courseassist/response",{content:content,heading:heading,action:"translate_text"});this.result.innerHTML=html;this.result.querySelector('[data-action="regenerate"]')?.addEventListener("click",e=>{e.preventDefault();this._translate(lang)})}async _showError(error,msg){if(!error){error=await Str.getString("error:defaultname","core_ai");msg=await Str.getString("error:defaultmessage","core_ai")}const html=await Templates.render("aiplacement_courseassist/error",{error:error,errorMessage:msg});this.result.innerHTML=html}_getPageText(){const el=document.querySelector(SEL.MAIN);return el?.innerText||el?.textContent||""}};return AITranslate}));

